#!/usr/bin/env python3
from pathlib import Path
import base64
import re
import shutil
import subprocess
import tempfile

MAIN = Path("lib/main.dart")
PUBSPEC = Path("pubspec.yaml")
TEST = Path("test/system_smoke_test.dart")

ASSETS = {"assets/pawns/13_minik_galaksi_bilgesi.png": "", "assets/pawns/14_fidan_muhafizi.png": "", "assets/pawns/15_ozgur_ev_cini.png": "", "assets/pawns/16_magara_sinsigi.png": ""}

def run(command):
    print("$ " + " ".join(command))
    return subprocess.run(command, check=True)

for path in [MAIN, PUBSPEC, TEST]:
    if not path.exists():
        raise SystemExit(
            f"Gerekli dosya bulunamadı: {path}\n"
            "Kurulumu BilgiRotasi deposunun ana klasöründe çalıştır."
        )

branch = subprocess.check_output(
    ["git", "branch", "--show-current"],
    text=True,
).strip()

if branch != "main":
    raise SystemExit(
        "Bu geliştirme yalnızca main dalına kurulabilir.\n"
        f"Şu anki dal: {branch or '(belirsiz)'}\n"
        "Önce: git switch main"
    )

question_status = subprocess.run(
    ["git", "status", "--porcelain", "--", "assets/questions.json"],
    text=True,
    capture_output=True,
    check=True,
).stdout.strip()

if question_status:
    raise SystemExit(
        "assets/questions.json dosyasında yerel değişiklik var.\n"
        "Soru çalışmalarını ayrı branch'te bırakıp main dalını "
        "temizledikten sonra bu paketi çalıştır."
    )

main = MAIN.read_text(encoding="utf-8")
pubspec = PUBSPEC.read_text(encoding="utf-8")
test = TEST.read_text(encoding="utf-8")

version_match = re.search(
    r"^version:\s*(\d+)\.(\d+)\.(\d+)\+(\d+)\s*$",
    pubspec,
    flags=re.MULTILINE,
)
if version_match is None:
    raise SystemExit("pubspec.yaml sürüm satırı okunamadı.")

version = tuple(map(int, version_match.groups()))
if version != (1, 37, 0, 47):
    raise SystemExit(
        "Bu düzeltme 1.37.0+47 sürümü için hazırlandı.\n"
        f"Depodaki sürüm: {version[0]}.{version[1]}.{version[2]}+{version[3]}"
    )

new_names = [
    "Minik Galaksi Bilgesi",
    "Fidan Muhafızı",
    "Özgür Ev Cini",
    "Mağara Sinsiği",
]
if any(name in main for name in new_names):
    raise SystemExit("Dört yeni özgün piyon zaten kurulmuş görünüyor.")

if "class PawnCatalog" not in main or "static const List<PawnDefinition> all = [" not in main:
    raise SystemExit("Mevcut PawnCatalog yapısı bulunamadı.")

backup_dir = Path(tempfile.mkdtemp(prefix="bilgi_rotasi_pawn_pack_v2_"))
asset_paths = [Path(path) for path in ASSETS]
committed = False

try:
    shutil.copy2(MAIN, backup_dir / "main.dart")
    shutil.copy2(PUBSPEC, backup_dir / "pubspec.yaml")
    shutil.copy2(TEST, backup_dir / "system_smoke_test.dart")

    for asset_path in asset_paths:
        asset_path.parent.mkdir(parents=True, exist_ok=True)
        if asset_path.exists():
            raise RuntimeError(f"Yeni piyon görseli zaten var: {asset_path}")
        asset_path.write_bytes(base64.b64decode(ASSETS[str(asset_path)]))

    catalog_start = main.index("class PawnCatalog")
    catalog_end = main.index(
        "\n  static PawnDefinition at",
        catalog_start,
    )
    catalog = main[catalog_start:catalog_end]

    if catalog.count("PawnDefinition(") < 12:
        raise RuntimeError("Mevcut piyon kataloğu beklenenden kısa.")

    insert_at = catalog.rfind("  ];")
    if insert_at < 0:
        raise RuntimeError("PawnCatalog kapanış noktası bulunamadı.")

    additions = """    PawnDefinition(
      name: 'Minik Galaksi Bilgesi',
      assetPath: 'assets/pawns/13_minik_galaksi_bilgesi.png',
      fallbackSymbol: '🌌',
    ),
    PawnDefinition(
      name: 'Fidan Muhafızı',
      assetPath: 'assets/pawns/14_fidan_muhafizi.png',
      fallbackSymbol: '🌱',
    ),
    PawnDefinition(
      name: 'Özgür Ev Cini',
      assetPath: 'assets/pawns/15_ozgur_ev_cini.png',
      fallbackSymbol: '🧦',
    ),
    PawnDefinition(
      name: 'Mağara Sinsiği',
      assetPath: 'assets/pawns/16_magara_sinsigi.png',
      fallbackSymbol: '💍',
    ),
"""

    catalog = catalog[:insert_at] + additions + catalog[insert_at:]
    main = main[:catalog_start] + catalog + main[catalog_end:]

    main, version_count = re.subn(
        r"Bilgi Rotası • Sürüm 1\.37\.0",
        "Bilgi Rotası • Sürüm 1.38.0",
        main,
        count=1,
    )
    if version_count != 1:
        raise RuntimeError("Ana menü sürüm yazısı güncellenemedi.")

    pubspec = re.sub(
        r"^version:\s*.*$",
        "version: 1.38.0+48",
        pubspec,
        count=1,
        flags=re.MULTILINE,
    )

    test_insert = """
    test('Piyon kataloğu dört yeni özgün karakter içerir', () {
      final names = PawnCatalog.all
          .map((pawn) => pawn.name)
          .toSet();

      expect(PawnCatalog.all.length, greaterThanOrEqualTo(16));
      expect(names, contains('Minik Galaksi Bilgesi'));
      expect(names, contains('Fidan Muhafızı'));
      expect(names, contains('Özgür Ev Cini'));
      expect(names, contains('Mağara Sinsiği'));
    });
"""
    group_end = test.rfind("  });\n}")
    if group_end < 0:
        raise RuntimeError("Test dosyası ekleme noktası bulunamadı.")
    test = test[:group_end] + test_insert + test[group_end:]

    MAIN.write_text(main, encoding="utf-8")
    PUBSPEC.write_text(pubspec, encoding="utf-8")
    TEST.write_text(test, encoding="utf-8")

    checks = {
        MAIN: new_names + ["Bilgi Rotası • Sürüm 1.38.0"],
        PUBSPEC: ["version: 1.38.0+48"],
        TEST: ["Piyon kataloğu dört yeni özgün karakter içerir"],
    }
    for path, markers in checks.items():
        content = path.read_text(encoding="utf-8")
        for marker in markers:
            if marker not in content:
                raise RuntimeError(f"Doğrulama başarısız: {path} / {marker}")

    for asset_path in asset_paths:
        if not asset_path.exists() or asset_path.stat().st_size < 10000:
            raise RuntimeError(f"Piyon görseli oluşturulamadı: {asset_path}")

    if shutil.which("dart"):
        run(["dart", "format", "lib/main.dart", "test/system_smoke_test.dart"])

    run(["git", "diff", "--check"])

    changed_paths = subprocess.check_output(
        ["git", "diff", "--name-only"],
        text=True,
    ).splitlines()
    if "assets/questions.json" in changed_paths:
        raise RuntimeError("Güvenlik kontrolü: questions.json değişmiş görünüyor.")

    if shutil.which("flutter"):
        run(["flutter", "pub", "get"])
        run(["flutter", "analyze", "--no-fatal-warnings", "--no-fatal-infos"])
        run(["flutter", "test"])
    else:
        print("ℹ️ Flutter bu ortamda bulunamadı; analiz ve test GitHub Actions'ta çalışacak.")

    files_to_stage = [
        "lib/main.dart",
        "test/system_smoke_test.dart",
        "pubspec.yaml",
        *[str(path) for path in asset_paths],
    ]
    if Path("pubspec.lock").exists():
        files_to_stage.append("pubspec.lock")

    run(["git", "add", *files_to_stage])

    changed = subprocess.run(
        ["git", "diff", "--cached", "--quiet"],
        check=False,
    ).returncode != 0
    if not changed:
        raise RuntimeError("Commit edilecek değişiklik bulunamadı.")

    run(["git", "commit", "-m", "Dort yeni ozgun piyon ekle v3"])
    committed = True
    run(["git", "push", "origin", "main"])

except Exception as error:
    if not committed:
        shutil.copy2(backup_dir / "main.dart", MAIN)
        shutil.copy2(backup_dir / "pubspec.yaml", PUBSPEC)
        shutil.copy2(backup_dir / "system_smoke_test.dart", TEST)

        for asset_path in asset_paths:
            if asset_path.exists():
                asset_path.unlink()

        reset_paths = [
            "lib/main.dart",
            "test/system_smoke_test.dart",
            "pubspec.yaml",
            *[str(path) for path in asset_paths],
        ]
        if Path("pubspec.lock").exists():
            reset_paths.append("pubspec.lock")

        subprocess.run(["git", "reset", "--", *reset_paths], check=False)

        if shutil.which("flutter"):
            subprocess.run(["flutter", "pub", "get"], check=False)

    print("")
    print("❌ Kurulum tamamlanamadı.")
    print(str(error))
    if committed:
        print("Commit oluşturuldu fakat push başarısız oldu. Tekrar dene: git push origin main")
    else:
        print("Dosyalar önceki hâline otomatik döndürüldü.")
    raise SystemExit(1)

finally:
    shutil.rmtree(backup_dir, ignore_errors=True)

print("")
print("✅ Minik Galaksi Bilgesi eklendi.")
print("✅ Fidan Muhafızı eklendi.")
print("✅ Özgür Ev Cini eklendi.")
print("✅ Mağara Sinsiği eklendi.")
print("✅ Dört yeni şeffaf PNG piyon görseli oluşturuldu.")
print("✅ Piyon seçim ekranı ve tahta mevcut katalog üzerinden otomatik güncellendi.")
print("✅ questions.json dosyasına dokunulmadı.")
print("✅ Yeni sürüm: 1.38.0+48")
print("✅ Değişiklikler GitHub main dalına gönderildi.")
